// Normalize Google contacts — handles your real data format
const COUNTRY_TZ = { IN: 'Asia/Kolkata', IE: 'Europe/Dublin' };
const DIAL_TO_COUNTRY = [
  { dial: '353', country: 'IE' },
  { dial: '91', country: 'IN' },
];

function extractFirstPhone(phoneNumbers) {
  if (!phoneNumbers) return null;
  // Try types in priority order
  const types = ['mobile', 'home', 'work', 'other', 'main', 'undefined'];
  for (const type of types) {
    const arr = phoneNumbers[type];
    if (Array.isArray(arr) && arr.length > 0 && arr[0]) return arr[0];
  }
  // Fallback: first value of any key
  for (const key of Object.keys(phoneNumbers)) {
    const arr = phoneNumbers[key];
    if (Array.isArray(arr) && arr.length > 0 && arr[0]) return arr[0];
  }
  return null;
}

function normalizePhone(raw) {
  if (!raw || typeof raw !== 'string') return null;
  let cleaned = raw.trim();

  // Skip junk like "tel:17565137" or emergency numbers
  if (cleaned.startsWith('tel:')) return null;
  if (/^\d{3}$/.test(cleaned)) return null; // e.g. "112"
  if (/^1800/.test(cleaned.replace(/\D/g, ''))) return null; // toll-free

  // Strip everything except digits and leading +
  cleaned = cleaned.replace(/[^\d+]/g, '');

  // Handle 00 prefix (international)
  if (cleaned.startsWith('00')) cleaned = '+' + cleaned.slice(2);

  // No country code → assume India (+91) since most contacts are Indian
  if (!cleaned.startsWith('+')) {
    // Strip leading 0 (local India format like 08194...)
    if (cleaned.startsWith('0')) cleaned = cleaned.slice(1);
    cleaned = '+91' + cleaned;
  }

  const e164 = cleaned.replace(/^\+/, '');

  // Sanity check length (E.164 is 8-15 digits)
  if (e164.length < 10 || e164.length > 15) return null;

  // Match dial code (check longer codes first: 353 before 91)
  for (const { dial, country } of DIAL_TO_COUNTRY) {
    if (e164.startsWith(dial)) {
      return { e164, country, timezone: COUNTRY_TZ[country] };
    }
  }
  return null; // Not IN or IE
}

function parseBirthday(bday) {
  if (!bday) return null;
  // Your format: "5/7/1998" or "11/8/undefined" (M/D/YYYY)
  if (typeof bday === 'string') {
    const parts = bday.split('/');
    if (parts.length !== 3) return null;
    const [m, d, y] = parts;
    const month = parseInt(m);
    const day = parseInt(d);
    const year = parseInt(y);
    if (!month || !day || month > 12 || day > 31) return null;
    const validYear = (isNaN(year) || year < 1900) ? 1900 : year;
    return `${String(validYear).padStart(4, '0')}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
  }
  // Object format {year, month, day}
  if (typeof bday === 'object' && bday.month && bday.day) {
    const year = bday.year || 1900;
    return `${String(year).padStart(4, '0')}-${String(bday.month).padStart(2, '0')}-${String(bday.day).padStart(2, '0')}`;
  }
  return null;
}

const results = [];
const skipped = { noPhone: 0, noBirthday: 0, badPhone: 0, outOfScope: 0 };

for (const item of $input.all()) {
  const person = item.json;

  const name = person.names?.displayName
    || person.names?.givenName
    || '(no name)';

  const phoneRaw = extractFirstPhone(person.phoneNumbers);
  if (!phoneRaw) { skipped.noPhone++; continue; }

  const phone = normalizePhone(phoneRaw);
  if (!phone) {
    if (phoneRaw.includes('+')) skipped.outOfScope++;
    else skipped.badPhone++;
    continue;
  }

  const birthdayStr = parseBirthday(person.birthdays);
  if (!birthdayStr) { skipped.noBirthday++; continue; }

  const emailRaw = person.emailAddresses;
  let email = null;
  if (emailRaw && typeof emailRaw === 'object') {
    for (const key of Object.keys(emailRaw)) {
      if (Array.isArray(emailRaw[key]) && emailRaw[key][0]) {
        email = emailRaw[key][0];
        break;
      }
    }
  }

  results.push({
    json: {
      google_resource_name: person.resourceName,
      full_name: name,
      phone_e164: phone.e164,
      email,
      birthday: birthdayStr,
      country_code: phone.country,
      timezone: phone.timezone,
      source: 'google',
      is_active: true,
    },
  });
}

console.log('Sync summary:', { kept: results.length, ...skipped });

if (results.length === 0) {
  return [{ json: { __empty: true, skipped } }];
}

return results;

